using Microsoft.ML.Data;

namespace ChurnPredictor.Models;

public class CustomerData
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    public string Churned { get; set; } = string.Empty;
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public class ChurnModelTrainer
{
    private readonly MLContext _mlContext;
    private readonly ILogger<ChurnModelTrainer> _logger;

    public ChurnModelTrainer(ILogger<ChurnModelTrainer> logger)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
    }

    public void TrainAndSave(string dataPath, string modelPath)
    {
        // Load data
        var dataView = _mlContext.Data.LoadFromTextFile<CustomerData>(
            dataPath, hasHeader: true, separatorChar: ',');

        // Split into train/test (80/20)
        var split = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

        // Build pipeline
        var pipeline = _mlContext.Transforms.Conversion.MapValue(
                "Label",
                new[] { new KeyValuePair<string, bool>("Yes", true), new KeyValuePair<string, bool>("No", false) },
                inputColumnName: "Churned")
            .Append(_mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
            .Append(_mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
                labelColumnName: "Label", featureColumnName: "Features"));

        // Train
        _logger.LogInformation("Training churn prediction model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on test set
        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation("Model evaluation metrics:");
        _logger.LogInformation("  AUC:      {AUC:F4}", metrics.AreaUnderRocCurve);
        _logger.LogInformation("  F1 Score: {F1:F4}", metrics.F1Score);
        _logger.LogInformation("  Accuracy: {Accuracy:F4}", metrics.Accuracy);

        // Save model
        _mlContext.Model.Save(model, dataView.Schema, modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", modelPath);
    }
}

