using Microsoft.Extensions.ML;
using ChurnPredictor.Models;
using ChurnPredictor.Services;

var builder = WebApplication.CreateBuilder(args);

// Register services
builder.Services.AddSingleton<ChurnModelTrainer>();

var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn_model.zip");

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath: modelPath, watchForChanges: false);

var app = builder.Build();

// Train model on startup
var dataPath = Path.Combine(app.Environment.ContentRootPath, "Data", "customers.csv");
var trainer = app.Services.GetRequiredService<ChurnModelTrainer>();
trainer.TrainAndSave(dataPath, modelPath);

app.MapGet("/", () => "Hello");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, PredictRequest request) =>
{
    var input = new CustomerData
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region ?? string.Empty,
        PurchaseHistory = request.PurchaseHistory
    };

    var prediction = pool.Predict(input);

    return Results.Ok(new
    {
        predictedLabel = prediction.PredictedLabel,
        probability = prediction.Probability,
        score = prediction.Score
    });
});

app.Run();

public record PredictRequest(float Age, float Income, string? Region, float PurchaseHistory);

