     {
         _mlContext = new MLContext(seed: 42);
         _logger = logger;
     }

     public void TrainAndSave(string dataPath, string modelPath)
     {
         // Load data
         var dataView = _mlContext.Data.LoadFromTextFile<CustomerData>(
             dataPath, hasHeader: true, separatorChar: ',');

