             .Append(_mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
             .Append(_mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
             .Append(_mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
                 labelColumnName: "Label", featureColumnName: "Features"));

         // Train
         _logger.LogInformation("Training churn prediction model...");
         var model = pipeline.Fit(split.TrainSet);

         // Evaluate on test set
         var predictions = model.Transform(split.TestSet);
         var metrics = _mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

